select * from (

    where patient_id = #{patientId}
      and memory_type = 'short'

        and session_id = #{sessionId}

    order by create_time desc, record_id desc
    limit #{limit}
) t
order by t.create_time asc, t.record_id asc


where patient_id = #{patientId}
  and memory_type = 'long'
order by create_time desc, record_id desc
limit #{limit}
